public class ClientPacketSender {
    private static final Identifier PACKET_ID = new Identifier("modid", "c2s_packet");
    public static void send(String message) {
        PacketByteBuf buf = PacketByteBufs.create();
        buf.writeString(message);
        ClientPlayNetworking.send(PACKET_ID, buf);
    }
}

public class ServerPacketSender {
    private static final Identifier PACKET_ID = new Identifier("modid", "s2c_packet");
    public static void send(ServerPlayerEntity player, String message) {
        PacketByteBuf buf = PacketByteBufs.create();
        buf.writeString(message);
        ServerPlayNetworking.send(player, PACKET_ID, buf);
    }
}

public class ServerPacketReceiver {
    public static void register() {
        ServerPlayNetworking.registerGlobalReceiver(PACKET_ID, (server, player, handler, buf, responseSender) -> {
            String message = buf.readString();
            server.execute(() -> {
                player.sendMessage(Text.literal("收到: " + message), false);
            });
        });
    }
}

public class ClientPacketReceiver {
    public static void register() {
        ClientPlayNetworking.registerGlobalReceiver(PACKET_ID, (client, handler, buf, responseSender) -> {
            String message = buf.readString();
            client.execute(() -> {
                if (client.player != null) {
                    client.player.sendMessage(Text.literal("收到: " + message), false);
                }
            });
        });
    }
}

